  ('real-estate-moex-00570', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依房屋稅條例規定，下列敘述何者錯誤？', '["合法登記之工廠供直接生產使用之自有房屋，免徵房屋稅", "受重大災害，毀損面積佔整棟面積五成以上，必須修復始能使用之私有房屋，免徵房屋稅", "房屋標準價格，每三年重行評定一次，並應依其耐用年數予以折舊，按年遞減其價格", "各級政府機關及地方自治機關之公有辦公房屋及其員工宿舍，免徵房屋稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00571', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '關於契稅稅率依契稅條例之規定，下列敘述何者錯誤？', '["買賣契稅為其契價百分之六", "贈與契稅為其契價百分之六", "占有契稅為其契價百分之六", "典權契稅為其契價百分之六"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00572', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '土地所有權人於出售土地後，依土地稅法規定，下列何種情形得申請就其已納土地增值稅額內， 退還其不足支付新購土地地價之數額？', '["土地所有權人於先購買土地後，自完成移轉登記之日起二年後，始行出售土地者", "其新購土地地價超過原出售土地地價，扣除繳納房地交易所得稅後之餘額者", "自耕之農業用地出售後，於二年內另行購買仍供自耕之農業用地者", "土地出售前一年內，曾供營業使用或出租者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00573', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依土地稅法規定，有關地價稅優惠稅率與減免，下列敘述何者錯誤？', '["依都市計畫法劃設並經目的事業主管機關核准供公眾停車使用之停車場用地，按千分之十計徵 地價稅", "經目的事業主管機關核准設立之私立公園、體育場所使用範圍內之土地，免徵地價稅", "公有土地按基本稅率徵收地價稅。但公有土地供公共使用者，免徵地價稅", "都市計畫公共設施保留地，在保留期間仍為建築使用者，除自用住宅用地依第17條之規定外， 統按千分之六計徵地價稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00574', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依平均地權條例規定，為促進土地利用，擴大辦理市地重劃，得獎勵土地所有權人自行組織重劃 會辦理市地重劃，下列對獎勵土地所有權人辦理市地重劃之敘述，何者錯誤？', '["減半收取土地權利變更登記及換發權利書狀費用", "土地所有權人參加自辦市地重劃所需費用，得向政府指定之銀行或實施平均地權基金申請低利貸款", "自辦市地重劃區抵費地出售時，不計徵土地增值稅", "免徵或減徵地價稅與田賦"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00575', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依都市計畫法之規定，關於都市計畫之變更，下列敘述何者正確？', '["都市計畫之變更，如直接限制一定區域人民之權利者，則其性質即屬公法上之觀念通知", "都市計畫之變更屬法規性質，並非行政處分，都市計畫個別變更範圍外之人民，如因都市計畫 個別變更致其權利或法律上利益受侵害時，無法提起行政訴訟以資救濟", "為適應國防或經濟發展之需要而變更都市計畫時，應以通盤檢討變更之方式辦理", "為避免重大災害之發生而變更都市計畫時，應以個案迅行變更之方式辦理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00576', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依非都市土地使用管制規則規定，關於區域計畫擬定機關核發開發許可後，直轄市或縣（市）政 府應報經區域計畫擬定機關廢止原開發許可之情形，下列敘述何者錯誤？', '["興辦事業計畫經目的事業主管機關廢止或依法失其效力、整地排水計畫之核准經直轄市或縣 （市）政府廢止或水土保持計畫之核准經水土保持主管機關廢止或依法失其效力", "申請人自行申請廢止", "與水源供應、鄰近之交通設施、排水系統、電力、電信及垃圾處理等公共設施及公用設備服務 未能相互配合者", "違反核定之土地使用計畫、目的事業或環境影響評估等相關法規，經該管主管機關提出要求處 分並經限期改善而未改善"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00577', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '關於規定地價，依平均地權條例之規定，下列敘述何者正確？', '["規定地價後，每三年重新規定地價一次。但必要時得延長之", "直轄市或縣（市）主管機關辦理規定地價或重新規定地價時，須分區調查最近一年之土地買賣 價格或收益價格", "土地所有權人申報之地價未滿公告地價百分之八十時，得徵收之", "土地所有權人未於公告期間申報地價者，以公告地價為其申報地價"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00578', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '都市計畫法有關公共設施保留地之規定，下列敘述何者正確？', '["公共設施保留地劃設逾二十五年未經政府取得者，得優先辦理徵收", "公共設施保留地，其地價補償以徵收當期毗鄰公共設施保留地之平均公告土地現值為準，必要 時得加成補償之", "都市計畫公共設施保留地臨時建築使用辦法，由直轄市、縣（市）政府定之", "依法指定之公共設施保留地，得繼續為原來之使用或改為妨礙目的較輕之使用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00579', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依平均地權條例之規定，土地所有權移轉或設定典權時，權利人及義務人應於訂定契約之日起幾日 內，檢同契約及有關文件，共同申請土地所有權移轉或設定典權登記，並共同申報其土地移轉現值？', '["10日", "20日", "30日", "40日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00580', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '關於原土地所有權人申請已徵收土地之收回權，依土地徵收條例規定，下列敘述何者錯誤？', '["被徵收之土地，依原徵收計畫開始使用後未滿五年，不繼續依原徵收計畫使用者", "原土地所有權人應於該管直轄市或縣（市）主管機關通知後三個月內繳還原受領之補償地價及 地價加成補償，逾期視為放棄收回權", "申請收回土地案件，應由該管直轄市或縣（市）主管機關受理", "被徵收之土地，徵收補償費發給完竣屆滿三年，未依徵收計畫開始使用者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00581', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '有關徵收補償，依土地徵收條例相關規定，下列敘述何者正確？', '["農作改良物之補償費，於農作改良物被徵收時與其孳息成熟時期相距在1年以內者，按成熟時 之孳息估定之", "徵收當期市價指徵收公告期滿次日起算第十日經地價評議委員會評定之當期市價", "建築改良物之補償費，按起造當時該建築改良物之重建價格估定之", "被徵收土地在都市計畫區內之公共設施保留地，應按毗鄰公共設施保留地之平均市價補償其地價"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00582', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '關於耕地終止租約與補償，依平均地權條例規定，下列敘述何者正確？', '["耕地出租人依規定終止租約收回耕地時，應補償承租人為改良土地所支付之費用及已收穫之農 作改良物", "耕地出租人依規定終止租約，實際收回耕地屆滿二年後，不依照使用計畫建築使用者，直轄市 或縣（市）政府得照價收買之", "耕地出租人依規定終止租約收回耕地時，承租人得向出租人請求按公告當期該土地之公告土地 現值三分之一之補償", "出租耕地經依法編為建築用地者，出租人為收回自行建築或出售作為建築使用時，得終止租約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00583', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲有A屋一棟，出租給乙居住使用。依土地法第100條之規定，出租人因下列何項情形，得收回房屋？', '["承租人乙因疾病、意外產生有長期住院療養之需要時", "承租人乙積欠租金額，以擔保金抵償之後，尚有1個月租金未繳時", "承租人乙違反民法第443條第1項規定，將該屋轉租給他高中同學時", "承租人乙因為工作調動，無法繼續居住時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00584', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '土地或建築改良物，自繼承開始之日起逾1年未辦理繼承登記者，依土地法之規定，其處理程序 何者正確？', '["經縣市地政機關查明後，應即公告繼承人於6個月內聲請登記；逾期仍未聲請者，得由地政機 關予以列冊管理", "繼承人占有或第三人占有無合法使用權者，於標售後喪失其占有之權利；土地或建築改良物租 賃期間超過5年者，於標售後以5年為限", "標售所得之價款應於國庫設立專戶儲存，繼承人得依其法定應繼分領取。逾 15 年無繼承人申 請提領該價款者，歸屬國庫", "標售土地或建築改良物前應公告 10 日，繼承人、合法使用人或其他共有人就其使用範圍依序 有優先購買權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00585', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲有A屋，與乙簽訂買賣契約但尚未為移轉登記，乙對甲的A屋移轉請求權申請預告登記。下列 敘述何者最正確？', '["該預告登記為保全登記、暫時登記，其登記免納登記費", "該預告登記，對於因繼承、強制執行、徵收、法院判決而為之新登記，無排除之效力", "預告登記完畢後，如甲將A屋移轉於丙，該處分絕對無效", "嗣後甲欲就A屋申辦抵押權次序變更登記時，應檢附乙的同意書，始得為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
